int main() {
    // Example 1: Comparing Integers
    int num1 = 30; // num1 holds an integer value of 30
    int num2 = 50; // num2 holds an integer value of 50
    printf("Example 1: %d\n", (num1 < num2));  // Outputs: 1 (true)

    // Example 2: Comparing Floating-Point Numbers
    double temperature1 = 18.5; // temperature1 holds a double value of 18.5
    double temperature2 = 25.0; // temperature2 holds a double value of 25.0
    printf("Example 2: %d\n", (temperature1 < temperature2));  // Outputs: 1 (true)

    // Example 3: Comparing Mixed Types (Int and Double)
    int a = 20;    // a holds an integer value of 20
    double b = 30.5; // b holds a double value of 30.5
    printf("Example 3: %d\n", (a < b));  // Outputs: 1 (true)

    return 0;
}
